class Solution:
    def smallestDistancePair(self, nums, k):
        dists = []
        n = len(nums)
        for i in range(n):
            for j in range(i + 1, n):
                dists.append(abs(nums[i] - nums[j]))
        dists.sort()
        return dists[k - 1]

