class Solution:
    def smallestDistancePair(self, nums, k):
        nums.sort()
        n = len(nums)
        def count(d):
            c = 0
            j = 0
            for i in range(n):
                while nums[i] - nums[j] > d:
                    j += 1
                c += i - j
            return c
        lo, hi = 0, nums[-1] - nums[0]
        while lo < hi:
            mid = (lo + hi) // 2
            if count(mid) >= k:
                hi = mid
            else:
                lo = mid + 1
        return lo

