var smallestDistancePair = function(nums, k) {
    nums.sort((a, b) => a - b);
    const n = nums.length;
    const count = (d) => {
        let c = 0, j = 0;
        for (let i = 0; i < n; i++) {
            while (nums[i] - nums[j] > d) j++;
            c += i - j;
        }
        return c;
    };
    let lo = 0, hi = nums[n - 1] - nums[0];
    while (lo < hi) {
        const mid = Math.floor((lo + hi) / 2);
        if (count(mid) >= k) hi = mid;
        else lo = mid + 1;
    }
    return lo;
};
